arguments.command:
MARKER_UTC="2026-02-19T18:11:59Z"; SESSION_ROOT="/home/ubuntu/.openclaw/agents/main/sessions";
echo "[SESSION_CANDIDATES by marker epoch ±300s]";
marker_epoch=$(date -u -d "$MARKER_UTC" +%s);
find "$SESSION_ROOT" -maxdepth 1 -type f -name "*.jsonl" -printf "%T@ %p\n" | awk -v m="$marker_epoch" '($1>=m-300 && $1<=m+300){print}' | sort -n | tail -n 30;

echo "[SESSION_CANDIDATES recent top 10]";
find "$SESSION_ROOT" -maxdepth 1 -type f -name "*.jsonl" -printf "%TY-%Tm-%TdT%TH:%TM:%TSZ  %p\n" | sort | tail -n 10
